import api from "./api";
import { getUserFromLocalStorage } from "./authService";

// Tạo Payment Intent cho thanh toán
export const createPaymentIntent = (orderId) => {
  return api.post("/payments/create-intent", { orderId }, {
    headers: getUserFromLocalStorage()
  });
};

// Xử lý thanh toán
export const processPayment = ({ orderId, paymentIntentId, walletAddress }) => {
  return api.post("/payments/process", {
    orderId,
    paymentIntentId,
    walletAddress,
  }, {
    headers: getUserFromLocalStorage()
  });
};

// Lấy trạng thái thanh toán
export const getPaymentStatus = (orderId) => {
  return api.get(`/payments/${orderId}/status`, {
    headers: getUserFromLocalStorage()
  });
};
